import{_ as a,c as t,a2 as p,o as s}from"./chunks/framework.BQmytedh.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"pages/Linux/Yum-update和upgrade的区别.md","filePath":"pages/Linux/Yum-update和upgrade的区别.md","lastUpdated":1732945848000}'),d={name:"pages/Linux/Yum-update和upgrade的区别.md"};function u(n,e,o,c,l,i){return s(),t("div",null,e[0]||(e[0]=[p('<h2 id="_1-区别" tabindex="-1">1 区别 <a class="header-anchor" href="#_1-区别" aria-label="Permalink to &quot;1 区别&quot;">​</a></h2><blockquote><p>yum update和yum upgrade的功能是一样的，都是将需要更新的package更新至软件源中的最新版。区别是 yum upgrade会删除旧版本的package，而yum update则会保留。因此如果软件依赖旧版本的package，最好是使用 yum update，确保不会出现兼容问题。</p></blockquote><h2 id="_2-升级" tabindex="-1">2 升级 <a class="header-anchor" href="#_2-升级" aria-label="Permalink to &quot;2 升级&quot;">​</a></h2><p>升级软件包的时候，如果不需要升级的内核，可以添加 exclude 参数过滤，例如centos的升级</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ yum --exclude=kernel* --exclude=centos-release* -y update</span></span></code></pre></div><p>或者直接修改配置文件 <code>/etc/yum.conf</code>, 在[main]配置添加配置项</p><blockquote><p>exclude=kernel* exclude=centos-release*</p></blockquote><p>之后重新执行</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ yum -y update</span></span></code></pre></div>',9)]))}const h=a(d,[["render",u]]);export{m as __pageData,h as default};
